import{_ as t,c as o,o as a,ah as d}from"./chunks/framework.RCw5T9E9.js";const p=JSON.parse('{"title":"Advanced capture mode","description":"","frontmatter":{"title":"Advanced capture mode"},"headers":[],"relativePath":"network/advanced.md","filePath":"network/advanced.md"}'),s={name:"network/advanced.md"};function n(r,e,i,c,l,h){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="advanced-capture-mode" tabindex="-1">Advanced capture mode <a class="header-anchor" href="#advanced-capture-mode" aria-label="Permalink to &quot;Advanced capture mode&quot;">​</a></h1><p>Under <strong>Options → Network</strong> you can choose the <strong>capture mode</strong> for network traffic:</p><table tabindex="0"><thead><tr><th>Mode</th><th>In the UI</th><th>What it means</th></tr></thead><tbody><tr><td><strong>Classic mode</strong></td><td>classic snapshot</td><td>Same limits as in-page interception: headers and bodies are only what page scripts can read (including <strong>CORS</strong> rules for cross-origin). See <a href="./general.html#display-limits">Working with requests</a>.</td></tr><tr><td><strong>Advanced mode</strong></td><td>extended capture</td><td>The extension requests <strong><code>webRequest</code></strong> access and enriches the request details with the <strong>full set</strong> of request and response headers as seen by the browser for the exchange—not only the subset exposed to the page.</td></tr></tbody></table><p><strong>Advanced mode</strong> (pinning headers, <strong>Header links</strong>, Advanced-only header visibility options) is available <strong>only in the Chrome / Edge extension</strong>.<br><strong>Standalone</strong> still runs without extended capture: the full header set via <strong><code>webRequest</code></strong> described below <strong>is not available</strong> there.</p><hr><h2 id="what-advanced-mode-adds-in-the-network-tab" tabindex="-1">What Advanced mode adds in the Network tab <a class="header-anchor" href="#what-advanced-mode-adds-in-the-network-tab" aria-label="Permalink to &quot;What Advanced mode adds in the Network tab&quot;">​</a></h2><ul><li><strong>Request and response headers</strong> in request details use the extended data (including headers not listed in <code>Access-Control-Expose-Headers</code>).</li><li><strong>Pinning header rows</strong> — a header name can be pinned <strong>to the top of the list</strong> separately for <strong>Request</strong> and <strong>Response</strong>. Pins are toggled from the <strong>row menu</strong> (three dots) when Advanced mode is on.</li><li><strong>Header links</strong> — for a given header name and request <strong>Host</strong>, open an external URL using a template; the <strong><code>{value}</code></strong> placeholder (and optional <strong>value pipeline</strong>) controls how the header text is inserted into the link. See <a href="#header-links">Header links</a> below.</li></ul><p>The <strong>Header links</strong> list, <strong>Pinned headers</strong> table, and <strong>Advanced headers</strong> options under <strong>Options → Network</strong> are shown <strong>only when Advanced mode is enabled</strong>, so Classic mode stays uncluttered.</p><hr><h2 id="header-links" tabindex="-1">Header links <a class="header-anchor" href="#header-links" aria-label="Permalink to &quot;Header links&quot;">​</a></h2><p>Each rule defines:</p><ul><li><strong>Header</strong> — HTTP header name (matched <strong>case-insensitively</strong>);</li><li><strong>Host</strong> — host of the request URL (normalized: no scheme or path, e.g. <code>api.example.com</code>);</li><li><strong>Link</strong> — URL template; placeholders are resolved as described in <strong><a href="#value-placeholder-and-pipelines">Value placeholder and pipeline</a></strong>.</li></ul><p>You can create and edit rules from the <strong>header row menu</strong> on the <strong>Network</strong> tab (Advanced) and from <strong>Options</strong> when a header rule group is selected.</p><h3 id="value-placeholder-and-pipelines" tabindex="-1">Value placeholder and pipeline <a class="header-anchor" href="#value-placeholder-and-pipelines" aria-label="Permalink to &quot;Value placeholder and pipeline {#value-placeholder-and-pipelines}&quot;">​</a></h3><p>Inside the <strong>Link</strong> field you can use:</p><ul><li><strong><code>{value}</code></strong> — insert the header value exactly as shown on the request card (same as a pipeline with no steps).</li><li><strong><code>{value|…}</code></strong> — run a <strong>pipeline</strong>: after <code>{value</code>, list steps separated by <strong><code>|</code></strong>; apply them <strong>left → right</strong>, then insert the result. Example: <code>{value|trim|urlencode}</code>.</li></ul><p>Use a <strong>pipe</strong> <code>|</code> between steps. The parser splits the chain at <code>|</code> only when the <strong>next</strong> segment starts with a <strong>known operation</strong> (see tables below). That way, a <code>|</code> <strong>inside a regex</strong> (e.g. alternation <code>a|b</code>) is usually fine, as long as the substring after a candidate split does not look like a new op.</p><p>If a step is invalid (e.g. bad regex), that step is skipped and the value is left unchanged for that step.</p><h4 id="no-argument-operations" tabindex="-1">No-argument operations <a class="header-anchor" href="#no-argument-operations" aria-label="Permalink to &quot;No-argument operations&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Op</th><th>Effect</th></tr></thead><tbody><tr><td><code>trim</code></td><td>Trim leading/trailing whitespace.</td></tr><tr><td><code>lower</code></td><td>Lowercase.</td></tr><tr><td><code>upper</code></td><td>Uppercase.</td></tr><tr><td><code>urlencode</code></td><td><code>encodeURIComponent</code>-style encoding for use in URL query parts.</td></tr><tr><td><code>urldecode</code></td><td>Decode URI component (<code>+</code> treated as space). Invalid escapes leave the value unchanged.</td></tr><tr><td><code>base64encode</code> / <code>base64decode</code></td><td>Base64 of UTF-8 bytes.</td></tr><tr><td><code>hexencode</code> / <code>hexdecode</code></td><td>Hex string ↔ UTF-8 bytes (<code>hexdecode</code> ignores whitespace).</td></tr><tr><td><code>md5</code></td><td>MD5 hex digest of UTF-8 input (sync).</td></tr><tr><td><code>sha1</code> / <code>sha256</code></td><td>SHA-1 / SHA-256 hex digest via <strong>Web Crypto</strong> (<code>crypto.subtle</code>). Requires a context where SubtleCrypto is available (e.g. <strong>HTTPS</strong> or extension pages); otherwise the digest step yields an empty string.</td></tr></tbody></table><h4 id="regex-and-replacement" tabindex="-1">Regex and replacement <a class="header-anchor" href="#regex-and-replacement" aria-label="Permalink to &quot;Regex and replacement&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Op</th><th>Syntax</th><th>Notes</th></tr></thead><tbody><tr><td><code>regex</code></td><td><code>regex:&lt;pattern&gt;</code></td><td><code>new RegExp(&lt;pattern&gt;)</code> (no flags in the syntax—add them inside the pattern if your engine supports it). Sets the <strong>last match</strong> for a following <code>replace</code>. On no match, the value becomes empty.</td></tr><tr><td><code>replace</code></td><td><code>replace:&lt;template&gt;</code></td><td>After <code>replace:</code>, substitute <code>$1</code>, <code>$2</code>, … from the <strong>last</strong> <code>regex</code> match. If there was no match, result is empty.</td></tr><tr><td><code>replaceRegex</code></td><td><code>replaceRegex:&lt;pattern&gt;:&lt;template&gt;</code></td><td><strong>Pattern</strong> and <strong>template</strong> are split at the <strong>last</strong> <code>:</code> in the segment—so a <code>:</code> inside the pattern is awkward; prefer <code>regex</code> + <code>replace</code> instead. Uses <code>String.replace</code> with a <code>RegExp</code>.</td></tr><tr><td><code>match</code></td><td><code>match:&lt;pattern&gt;</code></td><td>If the value matches, keep it; otherwise replace with empty string.</td></tr></tbody></table><h4 id="strings-and-structure" tabindex="-1">Strings and structure <a class="header-anchor" href="#strings-and-structure" aria-label="Permalink to &quot;Strings and structure&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Op</th><th>Syntax</th><th>Notes</th></tr></thead><tbody><tr><td><code>replaceText</code></td><td><code>replaceText:&lt;from&gt;:&lt;to&gt;</code></td><td><strong>From</strong> / <strong>to</strong> use the <strong>last</strong> <code>:</code> in the payload as separator between <code>to</code> and everything before it (<code>from</code> may contain <code>:</code>). Global replace of all <code>from</code> occurrences. Empty <code>from</code> skips the step.</td></tr><tr><td><code>substring</code></td><td><code>substring:&lt;start&gt;</code> or <code>substring:&lt;start&gt;:&lt;length&gt;</code></td><td>Same idea as <code>String.slice</code> / <code>substring</code>: with two numbers, length is a <strong>character count</strong> from <code>start</code>.</td></tr><tr><td><code>split</code></td><td><code>split:&lt;delimiter&gt;:&lt;index&gt;</code></td><td><strong>Index</strong> is the part after the <strong>last</strong> <code>:</code> (must be digits). <strong>Delimiter</strong> is everything before that <code>:</code> (may contain <code>:</code>). Empty part if index is out of range.</td></tr></tbody></table><h4 id="conditions-and-defaults" tabindex="-1">Conditions and defaults <a class="header-anchor" href="#conditions-and-defaults" aria-label="Permalink to &quot;Conditions and defaults&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Op</th><th>Syntax</th><th>Notes</th></tr></thead><tbody><tr><td><code>default</code></td><td><code>default:&lt;fallback&gt;</code></td><td>If the current value is exactly the <strong>empty string</strong> after previous steps, set it to <code>&lt;fallback&gt;</code>. To treat whitespace-only as empty, use <code>trim</code> first.</td></tr><tr><td><code>ifMatch</code></td><td><code>ifMatch:&lt;pattern&gt;:&lt;ifTrue&gt;:&lt;ifFalse&gt;</code></td><td><strong>False</strong> branch is after the <strong>last</strong> <code>:</code>; <strong>true</strong> branch is between the <strong>second-to-last</strong> and <strong>last</strong> <code>:</code>; <strong>pattern</strong> is everything before the <strong>second-to-last</strong> <code>:</code> (so colons inside branches are constrained by this rule).</td></tr></tbody></table><h3 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://trace.example.com/?id={value}</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://trace.example.com/?id={value|trim|urlencode}</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://trace.example.com/?t={value|regex:^Bearer\\s+(.+)$|replace:$1|urlencode}</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://trace.example.com/?t={value|default:unknown}</span></span></code></pre></div><p>Multiple placeholders in one template are allowed; each <code>{value...}</code> block is resolved independently using the <strong>same</strong> header value.</p><hr><h2 id="quick-recap" tabindex="-1">Quick recap <a class="header-anchor" href="#quick-recap" aria-label="Permalink to &quot;Quick recap&quot;">​</a></h2><ul><li><strong>Advanced mode</strong> extends headers via <strong><code>webRequest</code></strong>; <strong>Standalone</strong> does not provide this mode.</li><li><strong>Classic mode</strong> is the original “page-visible” header model.</li><li><strong>Pin</strong> — separate for <strong>Request</strong> / <strong>Response</strong> lists.</li><li><strong>Header links:</strong> <strong>Host</strong> + <strong>Link</strong> template: <strong><code>{value}</code></strong> or pipeline <strong><code>{value|op|…}</code></strong> for the header value.</li></ul>',35)])])}const u=t(s,[["render",n]]);export{p as __pageData,u as default};
